import{_ as a,o as i,c as l,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Airflow en produccion","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/airflow/11-airflow-en-produccion.md","filePath":"data-engineering/airflow/11-airflow-en-produccion.md","lastUpdated":1782521464000}'),r={name:"data-engineering/airflow/11-airflow-en-produccion.md"};function s(n,e,c,t,d,u){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="airflow-en-produccion" tabindex="-1">Airflow en produccion <a class="header-anchor" href="#airflow-en-produccion" aria-label="Permalink to &quot;Airflow en produccion&quot;">​</a></h1><p>Airflow en produccion requiere gobierno: dependencias, seguridad, escalado, backups, alertas y procesos de despliegue.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Metadata DB robusta.</li><li>Scheduler redundante si la version/despliegue lo permite.</li><li>Workers escalables.</li><li>Logs remotos.</li><li>Secret backend.</li><li>Autenticacion en UI.</li><li>Backups.</li><li>CI para DAGs.</li></ul><h2 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h2><p>Protege:</p><ul><li>UI.</li><li>Variables y conexiones.</li><li>Logs con datos sensibles.</li><li>Acceso de workers a sistemas externos.</li><li>Permisos de usuarios.</li></ul><h2 id="dependencias" tabindex="-1">Dependencias <a class="header-anchor" href="#dependencias" aria-label="Permalink to &quot;Dependencias&quot;">​</a></h2><p>Empaqueta dependencias:</p><ul><li>Imagen Docker versionada.</li><li><code>requirements.txt</code> controlado.</li><li>Constraints compatibles con Airflow.</li></ul><p>No instales librerias manualmente en servidores.</p><h2 id="escalado" tabindex="-1">Escalado <a class="header-anchor" href="#escalado" aria-label="Permalink to &quot;Escalado&quot;">​</a></h2><p>Escala segun:</p><ul><li>Numero de tasks.</li><li>Duracion media.</li><li>Concurrencia por DAG.</li><li>Limites de sistemas externos.</li></ul><p>Usa pools antes de aumentar workers sin control.</p><h2 id="backups" tabindex="-1">Backups <a class="header-anchor" href="#backups" aria-label="Permalink to &quot;Backups&quot;">​</a></h2><p>Necesitas backup de:</p><ul><li>Metadata DB.</li><li>Configuracion.</li><li>DAG repo.</li><li>Secrets en su gestor.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Staging antes de prod.</li><li>Alertas accionables.</li><li>Runbooks de scheduler caido y DAG critico fallido.</li><li>Versionar DAGs e imagenes.</li><li>No mezclar pipelines experimentales con criticos sin separacion.</li></ul>',20)])])}const m=a(r,[["render",s]]);export{h as __pageData,m as default};
